1732	\begin{lemma}
1733	[\(\mathrm{Gr}(r,d)\) is separated over \(\mathbb{Z}\)]
1734	  \label{lem:gr_separated}
1735	  \lean{AlgebraicGeometry.Grassmannian.isSeparated}
1736	  \uses{def:gr_glued_scheme, def:gr_transition}
1737	  % SOURCE: [Nitsure], \S 1, sub-section "Separatedness" (read from
1738	  % references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860).
1739	  % SOURCE QUOTE:
1740	  % "The intersection of the diagonal of $\grass(r,d)$ with $U^I\times U^J$
1741	  %  can be seen to be the closed subscheme $\Delta_{I,J}\subset U^I\times U^J$
1742	  %  defined by entries of the matrix formula $X^J_I\,X^I - X^J =0$,
1743	  %  and so $\grass(r,d)$ is a separated scheme."
1744	  \textit{Source: [Nitsure], \S 1.}
1745	  The structure morphism \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
1746	  (\cref{def:gr_glued_scheme}) is separated; equivalently, the diagonal
1747	  \(\Delta : \mathrm{Gr}(r,d) \to \mathrm{Gr}(r,d) \times_{\mathbb{Z}}
1748	  \mathrm{Gr}(r,d)\) is a closed immersion.
1749	\end{lemma}
