1923	\section{Out of scope}
1924	\label{sec:gr_out_of_scope}
1925	
1926	This chapter constructs the Grassmannian \emph{scheme} \(\mathrm{Gr}(r,d)\) over
1927	the absolute base \(\mathbb{Z}\) and establishes its smoothness, separatedness
1928	and properness. The following constructions are deferred to later chapters and
1929	are not treated here:
1930	\begin{itemize}
1931	  \item \textbf{The tautological/universal quotient} \(u : \mathcal{O}^{\oplus
1932	    r}_{\mathrm{Gr}(r,d)} \twoheadrightarrow \mathcal{U}\) and the determinant
1933	    line bundle \(\det \mathcal{U}\) with its Pl\"ucker embedding.
1934	  \item \textbf{The functor-of-points representability} of \(\mathrm{Gr}(r,d)\)
1935	    -- that it represents \(\mathrm{Grass}(r,d) =
1936	    \Quot^{d,\mathcal{O}_{\mathbb{Z}}}_{\oplus^r \mathcal{O}_{\mathbb{Z}} /
1937	    \mathbb{Z} / \mathbb{Z}}\); this is blueprinted as
1938	    \cref{thm:grassmannian_representable} in
1939	    \cref{chap:Picard_QuotScheme}.
1940	  \item \textbf{The relative version over a general base \(S\)} with a locally
1941	    free sheaf \(V\) of rank \(r\): the scheme \(\mathrm{Gr}_S(V,d)\) obtained by
1942	    base change and gluing over a trivialising cover of \(V\). The
1943	    absolute-over-\(\mathbb{Z}\) construction of this chapter is the input to
1944	    that base change.
1945	\end{itemize}

